// layoutAt returns the int-id at (r, c), or 0 if missing.
func layoutAt(l entities.Layout, r, c int) int64 {
	if r < 0 || r >= len(l) {
		return 0
	}
	row := l[r]
	if c < 0 || c >= len(row) {
		return 0
	}
	return row[c]
}

// cellLabel returns "" for empty cells, the id otherwise.
func cellLabel(l entities.Layout, r, c int) string {
	v := layoutAt(l, r, c)
	if v == 0 {
		return ""
	}
	return fmt.Sprintf("%d", v)
}

// marshalLayout serializes the layout into JSON for the hidden form input.
// Errors fall back to "[]"; the server-side validator will reject the
// resulting empty layout cleanly.
func marshalLayout(l entities.Layout) string {
	if l == nil {
		return "[]"
	}
	b, err := json.Marshal(l)
	if err != nil {
		return "[]"
	}
	return string(b)
}

